// ==============================
// helpers + Piece + componente (SIN PARTS)
// ==============================
function clamp01(x) {
  return x < 0 ? 0 : x > 1 ? 1 : x;
}

function computeAssembleFactor(v, IN_START, IN_END, OUT_START, OUT_END) {
  const fin = clamp01((v - IN_START) / (IN_END - IN_START));
  const fout = clamp01((OUT_END - v) / (OUT_END - OUT_START));
  return Math.min(fin, fout); // 0..1..0
}

// pieza “tirada” -> “armada”
export function Piece({
  i,
  factor,
  children,
  scatterPx = 14,
  rotateDeg = 18,
  origin = "85.5px 78px",

  // ✅ NUEVO (opcionales)
  scatterX,
  scatterY,
  rotateBy,
}) {
  const sx = ((i * 97) % 19) - 9;
  const sy = ((i * 57) % 17) - 8;
  const sr = ((i * 41) % 21) - 10;

  // fallback al comportamiento actual
  const baseX = sx * scatterPx;
  const baseY = sy * scatterPx;
  const baseR = sr * rotateDeg;

  const x = useTransform(factor, (t) => (1 - t) * (scatterX ?? baseX));
  const y = useTransform(factor, (t) => (1 - t) * (scatterY ?? baseY));
  const r = useTransform(factor, (t) => (1 - t) * (rotateBy ?? baseR));

  const opacity = useTransform(factor, [0, 0.15, 1], [0.25, 1, 1]);

  return (
    <motion.g style={{ x, y, rotate: r, opacity, transformOrigin: origin }}>
      {children}
    </motion.g>
  );
}

export default function ProcesosScatterAssemble({
  className = "",
  IN_START = 0.1,
  IN_END = 0.50,
  OUT_START = 1,
  OUT_END = 1,
  scatterPx = 14,
  rotateDeg = 18,
}) {
  const wrapRef = useRef(null);

  const { scrollYProgress } = useScroll({
    target: wrapRef,
    offset: ["start 115%", "end -5%"],
  });

  const factor = useMotionValue(0);

  useMotionValueEvent(scrollYProgress, "change", (v) => {
    factor.set(computeAssembleFactor(v, IN_START, IN_END, OUT_START, OUT_END));
  });

  const commonStroke = useMemo(
    () => ({
      vectorEffect: "non-scaling-stroke",
      strokeLinejoin: "round",
      strokeLinecap: "round",
    }),
    []
  );

  return (
    <div
      ref={wrapRef}
      className={`relative overflow-visible min-h-0 ${className}`}   // ✅ clave
      style={{ overflow: "visible" }}                                // ✅ clave
    >
      <style>{`
        .exclude-stroke{
          fill: none !important;
          stroke: #DEBB35 !important;
          stroke-width: 0.9 !important;
          vector-effect: non-scaling-stroke;
          stroke-linejoin: round;
          stroke-linecap: round;
        }
      `}</style>

      <motion.svg
        viewBox="0 0 171 156"
        fill="none"
        className="w-full h-auto overflow-visible"                  // ✅ clave
        preserveAspectRatio="xMidYMid meet"
        style={{ overflow: "visible" }}                              // ✅ clave
      >
{PARTS.filter((p) => p.id !== "Exclude").map((p, idx) => {
  // SOLO para esta llamada: en t=0 => 0, luego sube normal
  const pathOpacity = useTransform(factor, [0, 0.15, 1], [0, 1, 1]);

  return (
    <Piece
      key={p.id}
      i={idx}
      factor={factor}
      scatterPx={scatterPx}
      rotateDeg={rotateDeg}
      origin="85.5px 78px"
    >
      <motion.path
        d={p.d}
        fill={p.fill}
        style={{ ...commonStroke, opacity: pathOpacity }} // ✅ SOLO ACÁ
      />
    </Piece>
  );
})}

        <ExcludeScatterAssemble
          factor={factor}
          scatterPx={18}
          rotateDeg={22}
          delay={0}
          dur={0.6}
          stagger={0.02}
          staggerMax={0.45}
          startBlur={0}
          startOpacity={0}
        />
      </motion.svg>
    </div>
  );
}
